={
  "model": "llama-3.3-70b-versatile",
  "messages": [
    {
      "role": "system",
      "content": "You are an Intent Detection Agent. Analyze the user message and classify the intent.\n\nReturn STRICT JSON only:\n{\n  \"intent\": \"send_email\" | \"draft_email\" | \"chat\",\n  \"confidence\": 0.0 to 1.0,\n  \"entities\": {\n    \"recipient\": \"extracted name or email\",\n    \"topic\": \"what the email is about\",\n    \"urgency\": \"low\" | \"medium\" | \"high\"\n  },\n  \"original_text\": \"the user's message\"\n}"
    },
    {
      "role": "user",
      "content": "{{ $json.userText }}"
    }
  ],
  "temperature": 0.1,
  "max_tokens": 512
}

parameters.jsCode:
// Parse Intent Agent response
const items = $input.all();
const results = [];
for (const item of items) {
  try {
    const content = item.json.choices[0].message.content;
    let parsed;
    try {
      parsed = JSON.parse(content);
    } catch (e) {
      const match = content.match(/\{[\s\S]*\}/);
      parsed = match ? JSON.parse(match[0]) : { intent: 'chat', confidence: 0.5, entities: {} };
    }
    results.push({
      json: {
        intent: parsed.intent || 'chat',
        confidence: parsed.confidence || 0.5,
        entities: parsed.entities || {},
        originalText: parsed.original_text || item.json.userText || '',
        sessionId: item.json.sessionId || '',
      }
    });
  } catch (error) {
    results.push({
      json: { intent: 'chat', confidence: 0, entities: {}, error: error.message }
    });
  }
}
return results;

