  "messages": [
    {
      "role": "system",
      "content": "You are a Professional Email Composer Agent. Given the user's intent and details, compose a polished, professional email.\n\nReturn STRICT JSON only:\n{\n  \"to\": \"email@example.com\",\n  \"subject\": \"Clear, professional subject line\",\n  \"body\": \"Well-written professional email body with greeting and sign-off\",\n  \"response\": \"Brief friendly message to the user about the draft\"\n}"
    },
    {
      "role": "user",
      "content": "Compose an email based on this request: {{ $json.originalText }}\n\nDetected recipient: {{ $json.entities.recipient }}\nTopic: {{ $json.entities.topic }}\nUrgency: {{ $json.entities.urgency }}"
    }
  ],
  "temperature": 0.4,
  "max_tokens": 1024
}

parameters.jsCode:
// Parse Email Composer response and validate
const items = $input.all();
const results = [];
for (const item of items) {
  try {
    const content = item.json.choices[0].message.content;
    let parsed;
    try {
      parsed = JSON.parse(content);
    } catch (e) {
      const match = content.match(/\{[\s\S]*\}/);
      parsed = match ? JSON.parse(match[0]) : null;
      if (!parsed) throw new Error('Could not parse composer response');
    }

    // Validate email fields
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    const isValidEmail = emailRegex.test(parsed.to || '');

    results.push({
      json: {
        action: 'send_email',
        to: parsed.to || '',
        subject: parsed.subject || 'No Subject',
        body: parsed.body || '',
        response: parsed.response || 'I have drafted an email for you.',
        requiresConfirmation: true,
        isValidEmail: isValidEmail,
        sessionId: item.json.sessionId || '',
      }
    });
  } catch (error) {
    results.push({
      json: {
        action: 'chat',
        response: 'I had trouble composing the email. Could you please provide more details?',
        requiresConfirmation: false,
        error: error.message,
      }
    });
  }
}
return results;

